text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표 시점은 금요일 15:00 KST로 잡는다.",
        "condition": "스모크 테스트가 통과해야 한다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "condition": "계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경한다.",
        "status": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 공개 릴리스.",
        "status": "내부 스트레치 목표로만 언급됨",
        "note": "최종 결정은 아님."
      },
      {
        "goal": "README 설치 단계는 가능하면 목요일까지 검토.",
        "status": "희망 사항으로만 언급됨",
        "note": "담당자와 확정 기한이 정해지지 않음."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있음."
      },
      {
        "risk": "README 설치 단계가 오래된 경우 릴리스 노트가 사용자에게 잘못된 정보를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ],
    "non_decisions": [
      {
        "topic": "수요일 릴리스",
        "status": "확정되지 않음",
        "note": "내부 스트레치 목표로만 남음."
      },
      {
        "topic": "README 설치 단계 검토",
        "status": "확정되지 않음",
        "note": "가능하면 검토하자는 제안만 있었고 담당자는 정해지지 않음."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 노트를 `action_items.md`에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "pending",
      "source_certainty": "confirmed action, no exact deadline"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 결과",
      "생성된 tarball 경로",
      "README 설치 단계의 최신성 여부",
      "최종 릴리스 승인 권한자"
    ],
    "what_not_to_invent": [
      "고객사 또는 외부 파트너 이름",
      "예산 정보",
      "보안 사고 여부",
      "프로덕션 장애 여부",
      "법무 승인 요구사항",
      "확정되지 않은 담당자",
      "명시되지 않은 데드라인"
    ],
    "summary": "다음 확인 대상은 스모크 결과와 tarball 경로이며, 릴리스 승인자와 릴리스 노트에 내부 목표를 넣을지 여부는 아직 미결정이다."
  },
  "non_invention_rules": [
    "고객, 외부 파트너, 예산, 보안, 장애, 법무, 소유자, 기한은 원문에 없는 경우 절대 추가하지 않는다.",
    "수요일 릴리스는 최종 결정이 아니라 내부 스트레치 목표로만 기록한다.",
    "README 검토는 제안 수준으로만 기록하고 담당자와 마감 시점을 임의 지정하지 않는다.",
    "tarball 경로 확인은 Hara의 확인 작업으로만 기록하고 구체적 기한을 만들지 않는다.",
    "명시된 사실과 결정을 분리해 기록하고, 추정이나 해석은 '미결정' 또는 '가정 없음'으로 표시한다."
  ]
}
